import { z } from "zod";

// Mirror of providerSlugSchema from @repo/app-providers/client. Inlined because
// fumadocs-mdx's build-time loader can't resolve the package's extensionless
// re-exports under Node ESM. Keep in sync with packages/app-providers/src/client/display.ts.
const providerSlugSchema = z.enum([
  "apollo",
  "github",
  "vercel",
  "linear",
  "sentry",
]);

const AuthorSchema = z.object({
  name: z.string().min(1),
  url: z.url(),
  twitterHandle: z.string().min(1),
  jobTitle: z.string().min(1).optional(),
});

const FaqItemSchema = z.object({
  question: z.string().min(10),
  answer: z.string().min(20),
});

const HowToStepSchema = z.object({
  name: z.string().min(1),
  text: z.string().min(20),
  url: z.url().optional(),
});

const BasePageSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(50).max(160),
  keywords: z.array(z.string().min(1)).min(3).max(20),
  canonicalUrl: z.url(),
  ogTitle: z.string().min(1).max(70),
  ogDescription: z.string().min(50).max(160),
  noindex: z.boolean().default(false),
  nofollow: z.boolean().default(false),
});

const ContentPageSchema = BasePageSchema.extend({
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  faq: z.array(FaqItemSchema).min(1),
  featuredImage: z.string().startsWith("/images/").optional(),
});

export const BlogPostSchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/blog/"))
    .optional(),
  category: z.enum([
    "engineering",
    "product",
    "company",
    "tutorial",
    "research",
  ]),
  readingTimeMinutes: z.number().int().min(1),
  featured: z.boolean().default(false),
  tldr: z.string().min(20).max(300),
  howToSteps: z.array(HowToStepSchema).min(2).optional(),
});

export const ChangelogEntrySchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/changelog/"))
    .optional(),
  version: z.string().min(1),
  type: z.enum(["feature", "improvement", "fix", "breaking"]),
  tldr: z.string().min(20).max(300),
  improvements: z.array(z.string().min(1)).optional(),
});

export const LegalPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/legal/"))
    .optional(),
  updatedAt: z.iso.datetime(),
  effectiveAt: z.iso.datetime(),
});

const IntegrationStatusSchema = z.enum(["live", "beta", "coming-soon"]);
const IntegrationCategorySchema = z.enum([
  "dev-tools",
  "monitoring",
  "comms",
  "data",
  "project-management",
]);

export const IntegrationPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/integrations/"))
    .optional(),
  providerId: providerSlugSchema.optional(),
  tagline: z.string().min(10).max(120),
  category: IntegrationCategorySchema,
  featuredImage: z.string().startsWith("/images/").optional(),
  docsUrl: z.string().startsWith("/docs/").optional(),
  status: IntegrationStatusSchema.optional(),
  faq: z.array(FaqItemSchema).min(1).optional(),
  updatedAt: z.iso.datetime(),
});

export const DocsPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/docs/"))
    .optional(),
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  proficiencyLevel: z
    .enum(["Beginner", "Intermediate", "Advanced", "Expert"])
    .optional(),
});

// Inferred TypeScript types
export type BlogPostData = z.infer<typeof BlogPostSchema>;
export type ChangelogEntryData = z.infer<typeof ChangelogEntrySchema>;
export type LegalPageData = z.infer<typeof LegalPageSchema>;
export type DocsPageData = z.infer<typeof DocsPageSchema>;
export type IntegrationPageData = z.infer<typeof IntegrationPageSchema>;
export type IntegrationCategory = IntegrationPageData["category"];
export type IntegrationStatus = IntegrationPageData["status"];

// Fields required by the SEO layer — satisfied structurally by BlogPostData,
// ChangelogEntryData, and DocsPageData. Derived from BlogPostData so schema
// renames propagate here automatically.
export type ContentSeoData = Pick<
  BlogPostData,
  | "authors"
  | "description"
  | "keywords"
  | "nofollow"
  | "noindex"
  | "ogDescription"
  | "ogTitle"
  | "publishedAt"
  | "title"
  | "updatedAt"
>;

// Derived from Zod — Zod is the sole source of truth for these unions
export type BlogCategory = BlogPostData["category"];
// → "engineering" | "product" | "company" | "tutorial" | "research"

export type ChangelogType = ChangelogEntryData["type"];
// → "feature" | "improvement" | "fix" | "breaking"

import type { GraphContext } from "@vendor/seo/json-ld";
import type { Metadata } from "next";
import type { Crumb } from "./builders";
import {
  buildApiRefJsonLd,
  buildBlogPostJsonLd,
  buildChangelogEntryJsonLd,
  buildDocsJsonLd,
  buildIntegrationJsonLd,
  buildLegalJsonLd,
} from "./builders";
import type {
  BlogPostData,
  ChangelogEntryData,
  ContentSeoData,
  DocsPageData,
  IntegrationPageData,
  LegalPageData,
} from "./content-schemas";
import { createArticleMetadata, createMetadata } from "./content-seo";
import type {
  ApiRefUrl,
  BlogPostUrl,
  ChangelogUrl,
  DocsUrl,
  IntegrationUrl,
  LegalUrl,
} from "./url-types";

interface SeoBundle {
  readonly jsonLd: GraphContext;
  readonly metadata: Metadata;
}

// SeoBundle owns canonical URL derivation — derives from the typed url param,
// respects frontmatter canonicalUrl as an escape hatch.
// Both metadata.alternates.canonical and JSON-LD url come from the same value:
// drift is structurally impossible.

function buildArticleMetadata(
  data: ContentSeoData,
  canonicalUrl: string,
  titleSuffix: string,
  siteName: string,
  ogImageUrl?: string
): Metadata {
  return createArticleMetadata(
    {
      title: `${data.title} – ${titleSuffix}`,
      description: data.description,
      keywords: data.keywords,
      authors: data.authors.map((a) => ({ name: a.name, url: a.url })),
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        url: canonicalUrl,
        siteName,
        locale: "en_US",
        authors: data.authors.map((a) => a.url),
        ...(ogImageUrl && {
          images: [
            {
              url: ogImageUrl,
              width: 1200,
              height: 630,
              alt: data.ogTitle,
            },
          ],
        }),
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        ...(ogImageUrl && { images: [ogImageUrl] }),
      },
      category: "Technology",
    },
    { publishedAt: data.publishedAt, updatedAt: data.updatedAt }
  );
}

export function emitBlogPostSeo(
  data: BlogPostData,
  url: BlogPostUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Blog",
      "Lightfast Blog"
    ),
    jsonLd: buildBlogPostJsonLd(data, url),
  };
}

export function emitChangelogEntrySeo(
  data: ChangelogEntryData,
  url: ChangelogUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Changelog",
      "Lightfast Changelog"
    ),
    jsonLd: buildChangelogEntryJsonLd(data, url),
  };
}

export function emitDocsSeo(
  data: DocsPageData,
  url: DocsUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = url.replace("/docs/", "/docs/og/");
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Docs",
      "Lightfast Documentation",
      ogImageUrl
    ),
    jsonLd: buildDocsJsonLd(data, url, breadcrumbs),
  };
}

export function emitLegalSeo(data: LegalPageData, url: LegalUrl): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}

export function emitIntegrationSeo(
  data: IntegrationPageData,
  url: IntegrationUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = `${url}/opengraph-image`;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast Integrations`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast Integrations",
        locale: "en_US",
        images: [
          { url: ogImageUrl, width: 1200, height: 630, alt: data.ogTitle },
        ],
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [ogImageUrl],
      },
    }),
    jsonLd: buildIntegrationJsonLd(data, url),
  };
}

export function emitApiRefSeo(
  data: DocsPageData,
  url: ApiRefUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  const ogImageUrl = url.replace(
    "/docs/api-reference/",
    "/docs/api-reference/og/"
  );
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast API Reference",
      "Lightfast API Reference",
      ogImageUrl
    ),
    jsonLd: buildApiRefJsonLd(data, url, breadcrumbs),
  };
}

import type {
  BlogPosting,
  GraphContext,
  HowTo,
  HowToStep,
} from "@vendor/seo/json-ld";
import type { BlogCategory, BlogPostData } from "~/lib/content-schemas";
import type { BlogPostUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

// Exhaustive mapping — adding a new BlogCategory errors here until handled
const ARTICLE_SECTIONS: Record<BlogCategory, string> = {
  engineering: "Engineering",
  product: "Product",
  company: "Company",
  tutorial: "Tutorial",
  research: "Research",
};

function buildBlogPostEntity(
  data: BlogPostData,
  url: BlogPostUrl
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      ...(a.jobTitle ? { jobTitle: a.jobTitle } : {}),
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: `${url}/opengraph-image`,
      width: "1200",
      height: "630",
    },
    keywords: data.keywords.join(", "),
    articleSection: ARTICLE_SECTIONS[data.category],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

function buildHowToEntity(data: BlogPostData, url: BlogPostUrl): HowTo {
  // biome-ignore lint/style/noNonNullAssertion: caller guards on howToSteps presence
  const steps = data.howToSteps!;
  return {
    "@type": "HowTo",
    "@id": `${url}#howto`,
    name: data.title,
    description: data.tldr,
    step: steps.map(
      (s, index) =>
        ({
          "@type": "HowToStep" as const,
          position: index + 1,
          name: s.name,
          text: s.text,
          ...(s.url ? { url: s.url } : {}),
        }) satisfies HowToStep
    ),
  };
}

export function buildBlogPostJsonLd(
  data: BlogPostData,
  url: BlogPostUrl
): GraphContext {
  const entity = buildBlogPostEntity(data, url);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#article`, url },
      ...(data.faq.length > 0 ? [buildFaqEntity(data.faq, url)] : []),
      ...(data.howToSteps && data.howToSteps.length > 0
        ? [buildHowToEntity(data, url)]
        : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Blog", url: "https://lightfast.ai/blog" },
        { name: data.title, url },
      ]),
    ],
  };
}

