    articleSection: meta.title,
  }));

  const itemList: ItemList = {
    "@type": "ItemList",
    "@id": itemListId,
    itemListOrder: "https://schema.org/ItemListOrderDescending",
    numberOfItems: posts.length,
    itemListElement: posts.map(
      (p, idx): ListItem => ({
        "@type": "ListItem",
        position: idx + 1,
        url: `https://lightfast.ai/blog/${p.slug}`,
