      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast Integrations",
        locale: "en_US",
        images: [
          { url: ogImageUrl, width: 1200, height: 630, alt: data.ogTitle },
        ],
      },
      twitter: {
        card: "summary_large_image",
